import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, TransformControls, Box, Plane, Grid, Sphere } from '@react-three/drei';
import * as THREE from 'three';

// --- 3D Components ---
const PadelCourt3D = () => (
  <group>
    <Plane args={[10, 20]} rotation={[-Math.PI / 2, 0, 0]} position={[0, 0, 0]}>
      <meshStandardMaterial color="#1b5e20" />
    </Plane>
    <Grid args={[10, 20]} position={[0, 0.01, 0]} sectionColor="white" cellColor="#2e7d32" />
    <Box args={[10, 0.88, 0.05]} position={[0, 0.44, 0]}>
      <meshStandardMaterial color="white" transparent opacity={0.6} />
    </Box>
  </group>
);

const VirtualCameraIcon = ({ config, setConfig }: { config: any, setConfig: (c: any) => void }) => {
  const meshRef = useRef<THREE.Mesh>(null!);
  return (
    <TransformControls 
      position={[config.pos_x - 5, config.height, config.pos_y - 10]} 
      mode="translate" 
      onMouseUp={() => {
        if (meshRef.current) {
          const pos = meshRef.current.position;
          setConfig({ ...config, pos_x: pos.x + 5, pos_y: pos.z + 10, height: pos.y });
        }
      }}
    >
      <Sphere args={[0.4]} ref={meshRef}><meshStandardMaterial color="yellow" /></Sphere>
    </TransformControls>
  );
};

// --- Math: 3D to 2D Projection ---
const projectPoint = (x: number, y: number, z: number, config: any, width: number, height: number) => {
    // Simplified perspective projection for the UI overlay
    const f = 1000; // Focal length
    const cx = width / 2;
    const cy = height / 2;

    // Relative to camera
    const dx = x - config.pos_x;
    const dy = z - config.pos_y;
    const dz = y - config.height;

    // Rotation (Tilt/Pan)
    const tilt = config.tilt * (Math.PI / 180);
    const ry = dy * Math.cos(tilt) - dz * Math.sin(tilt);
    const rz = dy * Math.sin(tilt) + dz * Math.cos(tilt);

    if (rz > 0) return null; // Behind camera

    const screenX = (dx * f) / -rz + cx;
    const screenY = (ry * f) / -rz + cy;
    return { x: screenX, y: screenY };
};

const App = () => {
  const [camera, setCamera] = useState({ id: 'cam1', pos_x: 5, pos_y: 25, height: 6, tilt: -35 });
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Court Lines for the "Ghost Overlay" (Meters)
  const courtLines = [
    [[0,0], [10,0]], [[10,0], [10,20]], [[10,20], [0,20]], [[0,20], [0,0]], // Perimeter
    [[0,10], [10,10]], // Net
    [[0, 6.95], [10, 6.95]], [[0, 13.05], [10, 13.05]], // Service Lines
    [[5, 6.95], [5, 13.05]] // Center Line
  ];

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.strokeStyle = '#00ff00';
    ctx.lineWidth = 2;

    courtLines.forEach(line => {
      const p1 = projectPoint(line[0][0], 0, line[0][1], camera, canvas.width, canvas.height);
      const p2 = projectPoint(line[1][0], 0, line[1][1], camera, canvas.width, canvas.height);

      if (p1 && p2) {
        ctx.beginPath();
        ctx.moveTo(p1.x, p1.y);
        ctx.lineTo(p2.x, p2.y);
        ctx.stroke();
      }
    });
  }, [camera]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: '#000', color: '#fff', fontFamily: 'sans-serif' }}>

      {/* 1. Video & Ghost Overlay */}
      <div style={{ flex: 2, position: 'relative', background: '#111', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        {!videoUrl ? (
          <div style={{ textAlign: 'center' }}>
             <h3>Step 1: Upload Padel Video</h3>
             <input type="file" accept="video/*" onChange={(e) => setVideoUrl(URL.createObjectURL(e.target.files![0]))} />
          </div>
        ) : (
          <>
            <video ref={videoRef} src={videoUrl} style={{ width: '100%', maxHeight: '100%' }} controls muted />
            <canvas ref={canvasRef} width={1280} height={720} style={{ position: 'absolute', pointerEvents: 'none', width: '100%', height: 'auto' }} />
          </>
        )}
      </div>

      {/* 2. 3D Minimap (Digital Twin) */}
      <div style={{ flex: 1, borderLeft: '2px solid #333', display: 'flex', flexDirection: 'column' }}>
        <div style={{ height: '50%', borderBottom: '2px solid #333' }}>
            <Canvas camera={{ position: [15, 15, 15] }}>
                <ambientLight intensity={0.5} />
                <PadelCourt3D />
                <VirtualCameraIcon config={camera} setConfig={setCamera} />
                <OrbitControls makeDefault />
            </Canvas>
        </div>

        {/* 3. Controls */}
        <div style={{ padding: '20px', overflowY: 'auto' }}>
            <h2>Calibration</h2>
            <p>Adjust the camera in 3D (left) until the <b>green lines</b> match the video court.</p>

            <label>Tilt: {camera.tilt}°</label>
            <input type="range" min="-90" max="0" value={camera.tilt} onChange={(e) => setCamera({...camera, tilt: parseInt(e.target.value)})} style={{ width: '100%' }} />

            <label style={{marginTop: '10px', display: 'block'}}>Height: {camera.height.toFixed(1)}m</label>
            <input type="range" min="1" max="15" step="0.1" value={camera.height} onChange={(e) => setCamera({...camera, height: parseFloat(e.target.value)})} style={{ width: '100%' }} />

            <div style={{ marginTop: '20px', padding: '10px', background: '#222', borderRadius: '5px' }}>
                <div style={{ color: '#4caf50', fontWeight: 'bold' }}>SCORE: 0 - 0</div>
                <div style={{ fontSize: '12px', color: '#aaa' }}>Waiting for analysis...</div>
            </div>

            <button 
                onClick={() => alert("Analysis started on backend!")}
                style={{ width: '100%', marginTop: '20px', padding: '15px', background: '#4caf50', border: 'none', color: '#fff', cursor: 'pointer', fontWeight: 'bold' }}>
                START AUTO-SCORING
            </button>
        </div>
      </div>
    </div>
  );
};

export default App;
